template <typename Program, typename Shader>
template <typename Device, typename Layout, typename Resolver>
Shaders<Program, Shader>::Shaders(Device &device, Layout &layout, const Resolver &resolver)
{
	(void)resolver;
	layout.unserialize(reflection_bank + 0, 348);
	this->composite = device.request_program(spirv_bank + 0, 126616, &layout);
	layout.unserialize(reflection_bank + 348, 348);
	this->blit = device.request_shader(spirv_bank + 31654, 1148, &layout);
	layout.unserialize(reflection_bank + 696, 348);
	this->bloom = device.request_shader(spirv_bank + 31941, 12280, &layout);
	layout.unserialize(reflection_bank + 1044, 348);
	this->scan = device.request_shader(spirv_bank + 35011, 5796, &layout);
	layout.unserialize(reflection_bank + 1392, 348);
	this->sinc[0] = device.request_shader(spirv_bank + 36460, 4612, &layout);
	layout.unserialize(reflection_bank + 1740, 348);
	this->sinc[1] = device.request_shader(spirv_bank + 37613, 6004, &layout);
	if (resolver("iir", "SUBGROUP") == 0)
	{
		layout.unserialize(reflection_bank + 2088, 348);
		this->iir = device.request_program(spirv_bank + 39114, 4828, &layout);
	}
	if (resolver("iir", "SUBGROUP") == 1)
	{
		layout.unserialize(reflection_bank + 2436, 348);
		this->iir = device.request_program(spirv_bank + 40321, 6376, &layout);
	}
}
